  ('EJA-LIBR-095', 'Apontar as semelhanças da escrita de língua de sinais apresentando suas particularidades relacionadas à emissão do sinal.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-096', 'Orientar e conduzir de forma clara os momentos de leitura e escrita de sinais.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-097', 'Realizar leitura de sinais e frases curtas em escrita de língua de sinais.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-098', 'Participar de diálogos em conversa sobre temas como vivências diárias, explorando a compreensão e a produção sinalizada.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-099', 'Observar a produção de diálogos, discriminando a análise das características que diferem da sinalização espontânea.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-100', 'Conhecer e explorar a diversidade cultural no Brasil e as regionalidades com relação ao uso da Libras.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-101', 'Conhecer e identificar a diversidade cultural no Brasil e as regionalidades com relação ao uso da Libras.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-102', 'Explorar o uso da prosódia na Libras com apresentação de histórias em Libras, enfatizando os aspectos não manuais que indicam a dinâmica interpretativa do texto sinalizado com prosódia emocional – alegria, raiva, surpresa, tristeza.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-103', 'Realizar o uso da prosódia na Libras com apresentação de histórias em Libras, enfatizando os aspectos não manuais que indicam a dinâmica interpretativa do texto sinalizado com prosódia emocional – alegria, raiva, surpresa, tristeza.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-104', 'Explorar em Libras mecanismos de flexão de gênero e número em atividades de contação de histórias.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-105', 'Reconhecer e utilizar em Libras mecanismos de flexão de gênero e número em atividades de contação de histórias.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
