  ('EJA-LIBR-115', 'Saber incorporar personagens de forma adequada ao registro linguístico e à situação de sinalização.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-116', 'Conhecer e explorar os elementos de uma narrativa (personagem, enredo, tempo e Segmentar um texto em Libras em partes de sentido, como eventos ou cenas em uma narrativa, ampliando gradativamente a complexidade.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-117', 'Explorar e conversar em Libras temas de interesse escolhidos pelo grupo ou propostos pelo professor sobre atualidades com uso de recursos diversos.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-118', 'Conversar e expor opiniões sobre temas de interesse escolhidos pelo grupo ou propostos pelo professor sobre a atualidade com uso de recursos diversos.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-119', 'Produzir vídeos apresentando opiniões e formulando perguntas e respostas sobre temas propostos pelos estudantes.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-120', 'Saber opinar e apreciar a opinião pessoal de diferentes interlocutores em um diálogo.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
