  ('EJA-LIBR-123', 'Conhecer, por meio de visitas, espaços culturais diversos como museus, teatros e exposições com acessibilidade.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-124', 'Participar de atividades e eventos que envolvam interação linguística com pessoas surdas fora do contexto escolar, bem como saraus com diversas manifestações artísticas baseadas na Libras.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
  ('EJA-LIBR-125', 'Conhecer a trajetória dos surdos até os dias Refletir e discutir em momentos de rodas de conversas sobre movimentos surdos da história e da atualidade.', 'Linguagens', 'EJA', 'LIBRAS: EMISSÃO E RECEPÇÃO', 'qsn'),
